-- 2. Sevenoaks District × SEO
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'seo',
  'sevenoaks-district',
  'Sevenoaks District presents a unique SEO challenge: a wealthy, discerning population of around 120,000 spread across a main town and multiple villages, each generating distinct search patterns. When an Otford resident searches for a kitchen fitter, they use different terms than someone in Edenbridge looking for the same service. A Westerham homeowner searching for a solicitor has different expectations than one in Sevenoaks town. Most businesses in the district have no SEO strategy at all, relying on reputation and word of mouth to sustain them. But the demographic is shifting. Younger professionals moving into the area search online for everything, and the businesses that appear at the top of Google for village-specific and district-wide searches capture the highest-value clients. Our SEO campaigns are built around the specific search geography of Sevenoaks District, targeting the terms and locations that actually drive revenue across this affluent catchment.',
  'Sevenoaks District''s search landscape is shaped by its geography and wealth profile. The main town of Sevenoaks generates the highest volume of commercial searches, but the satellite towns and villages of Westerham, Edenbridge, Otford, Kemsing, and Seal each produce their own distinct search demand. Tourism-related searches centre on Knole House, Chartwell, and the Kent Downs AONB. The professional services sector generates B2B searches, while the high property values drive constant demand for home improvement, renovation, and luxury interior services. The twenty-four-minute commute to London means many searches happen during travel or in the evening.',
  'SEO competition in Sevenoaks District is concentrated in a few sectors. Financial advisers, estate agents, and solicitors along the High Street and London Road have invested in search visibility over many years, creating strong domain authority that is difficult to displace. However, the village-level search landscape is largely uncontested, with enormous opportunity for businesses willing to target Westerham, Edenbridge, Otford, and surrounding areas. National directories dominate many service searches that local businesses should own.',
  'We approach Sevenoaks District SEO as a multi-location discipline. Rather than targeting only the main town, we build campaigns that capture searches across every settlement in the district. A builder who serves the whole area needs pages targeting Sevenoaks, Westerham, Edenbridge, and the villages individually. A professional firm needs to rank for district-wide terms while also capturing village-level searches. We combine Google Business Profile optimisation, location-specific content, and technical SEO to build authority across the full catchment.',
  '{"population": 120000, "growth": "Stable with high property turnover driving service demand", "business_districts": ["Sevenoaks High Street", "London Road", "Westerham", "Edenbridge"], "key_fact": "Village-level searches are largely uncontested — major opportunity gap"}',
  '[{"title": "Invisible beyond Sevenoaks town centre searches", "description": "Most businesses in Sevenoaks District only appear in search results for the main town. They are completely invisible to residents of Westerham, Edenbridge, Otford, Kemsing, and Seal who search for services using their own village name. This means losing potential clients across a 120,000-person catchment to competitors who do target these areas."}, {"title": "Affluent searchers choosing competitors who rank first", "description": "Sevenoaks District''s high-net-worth residents value their time. They do not scroll through three pages of Google results. They contact the top two or three results and expect prompt, professional responses. Businesses not appearing in these top positions are invisible to the district''s most valuable potential clients."}, {"title": "National directories capturing Sevenoaks District search traffic", "description": "Platforms like Checkatrade, Bark, and Houzz aggressively target Sevenoaks keywords because the affluent demographic represents high-value leads. Local businesses without SEO strategies are pushed below these aggregators, losing direct enquiries and paying referral fees for leads that should be free."}]',
  '[{"title": "Multi-village SEO strategy covering the full Sevenoaks District", "description": "We build location-specific pages and content targeting every settlement in the district: Sevenoaks, Westerham, Edenbridge, Otford, Kemsing, and Seal. Each page is optimised for the specific search terms residents of that area use, capturing the full 120,000-person catchment rather than just the main town."}, {"title": "Google Business Profile dominance across district postcodes", "description": "We optimise your Google Business Profile with precise service area targeting covering the entire Sevenoaks District. Combined with a structured review generation programme and local citation building across Kent directories, we position your business in the map pack for searches across every village and town in the area."}, {"title": "Authority-building content for Sevenoaks District''s premium market", "description": "We create content demonstrating genuine expertise and local knowledge across the district. Blog posts referencing Knole House, the Kent Downs, Chartwell, and specific village characteristics signal to Google that your business is a genuine local authority, not a distant competitor trying to target the area remotely."}]',
  '[{"question": "Can you help me rank in villages like Otford and Westerham, not just Sevenoaks?", "answer": "Absolutely. Village-level SEO is one of our core strengths. We build dedicated pages for each settlement you serve across the district. These village-specific searches typically have less competition than main-town terms, meaning faster results and lower-cost visibility across the entire Sevenoaks District catchment."}, {"question": "How long before I see SEO results in Sevenoaks District?", "answer": "Village-level terms often show movement within six to eight weeks due to lower competition. More competitive Sevenoaks town-centre keywords typically require four to six months. We focus on quick wins first to build momentum while working toward the more competitive terms."}, {"question": "Why should I invest in SEO when my Sevenoaks business runs on referrals?", "answer": "Referrals are valuable, but they are unpredictable and do not scale. The younger professionals moving into Sevenoaks District search online even after receiving a personal recommendation. SEO ensures that when someone checks your business after a referral, they find a strong, authoritative online presence that confirms the recommendation."}, {"question": "Do you build backlinks for Sevenoaks District businesses?", "answer": "Yes. We build quality backlinks from Kent-based publications, local business directories, community organisations, and relevant industry sites. For Sevenoaks District businesses, links from sources like Kent Life, Visit Kent, and local chamber of commerce pages carry genuine authority with Google."}]',
  'authority'
)
