-- 6. Sevenoaks District × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'sevenoaks-district',
  'Social media across Sevenoaks District operates through a network of village-level community groups and local recommendation pages that drive real business. Facebook groups for Sevenoaks, Westerham, Edenbridge, Otford, and surrounding areas are where residents ask for trusted tradespeople, recommend restaurants, and share experiences with local service providers. Instagram is where the district''s independent boutiques, cafes, and artisan businesses build followings among an audience that values quality and aesthetics. Yet most businesses across the district either have no social media presence or maintain dormant profiles that create a worse impression than having no profile at all. We build, optimise, and brand your social media profiles so your business is ready to be found and recommended across the entire Sevenoaks District community.',
  'Sevenoaks District''s social media landscape is defined by its village structure. Each settlement has its own active Facebook community group where recommendations carry genuine weight. The Sevenoaks Chronicle and local community pages share news that drives engagement. Instagram is particularly important in this affluent area for businesses with a visual component, from interior designers to garden landscapers to independent restaurants. LinkedIn is relevant for the substantial professional and financial services sector. The district''s community events, from the Sevenoaks Summer Festival to village fetes, create seasonal social media opportunities that engaged businesses can leverage.',
  'Social media maturity across Sevenoaks District is uneven. Some High Street retailers and hospitality businesses maintain polished Instagram feeds, but many professional services firms have no social presence at all. Trades businesses vary from those with active Facebook profiles and strong review counts to those with dormant pages last updated years ago. The village-level businesses in Otford, Kemsing, and Seal are particularly underrepresented online, creating clear opportunity for those willing to establish a professional presence.',
  'We set up social media for Sevenoaks District businesses based on where their specific audience engages. Professional services get LinkedIn company pages built for the commuter demographic. Trades targeting homeowners across the villages get Facebook profiles optimised for community group engagement. Lifestyle and hospitality businesses get Instagram accounts designed to showcase quality in a way that resonates with the district''s aesthetically conscious audience. Every profile is branded consistently and optimised for local discovery.',
  '{"population": 120000, "growth": "Active village-level community groups drive recommendations", "business_districts": ["Sevenoaks High Street", "Westerham", "Edenbridge", "Otford", "Seal"], "key_fact": "Village Facebook groups are primary recommendation channels for local services"}',
  '[{"title": "Missing from village community group recommendations", "description": "When a Westerham resident asks their Facebook group for a reliable electrician, or an Otford parent requests a tutor recommendation, businesses without social media profiles are invisible. These community group recommendations drive genuine, high-value referrals across the district, and businesses without profiles cannot participate."}, {"title": "Dormant profiles undermining trust with affluent audience", "description": "A Sevenoaks District business with a Facebook page last updated two years ago sends a clear signal to the quality-conscious local audience: this business is not active or does not care about its public image. In a district where perception equals reality, a neglected profile is worse than none."}, {"title": "No visual platform presence for aesthetically-driven market", "description": "Interior designers, landscapers, restaurants, and boutiques across Sevenoaks District without an Instagram presence miss the primary platform where their affluent audience discovers and evaluates businesses with a visual component. The district''s aesthetic-conscious demographic expects to see your work before making contact."}]',
  '[{"title": "Village-network social media setup for district-wide reach", "description": "We build Facebook business profiles optimised for engagement across every village community group in the Sevenoaks District. Professional branding, complete service area information, and portfolio content ensure that when your business is mentioned or recommended in an Otford, Westerham, or Sevenoaks group, the profile converts that recommendation into an enquiry."}, {"title": "Premium Instagram presence for visually-led businesses", "description": "For Sevenoaks District businesses with a visual element, from interiors to gardens to food, we create Instagram profiles with professional imagery templates, consistent aesthetic guidelines, and a content plan that showcases your work to the district''s quality-conscious audience."}, {"title": "LinkedIn setup for professional services targeting commuters", "description": "For financial advisers, solicitors, accountants, and consultants in Sevenoaks District, we build LinkedIn company pages that project credibility to the commuter demographic. These professionals evaluate local service providers with the same rigour they apply to business partners, and your LinkedIn presence must meet that standard."}]',
  '[{"question": "Which social platforms matter most for Sevenoaks District businesses?", "answer": "For trades and home services, Facebook is essential due to the village community groups. For lifestyle, hospitality, and design businesses, Instagram is primary. For professional and financial services, LinkedIn reaches the commuter demographic. We recommend the platforms that match your specific audience within the district."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service focuses on professional setup: creating, branding, and optimising your profiles for the Sevenoaks District market. We provide content templates and a posting guide for ongoing maintenance. Continuous management is available as a separate service if you prefer a hands-off approach."}, {"question": "Can you set up profiles for multiple village areas?", "answer": "Yes. We ensure your profiles target the full district, with service area information covering Sevenoaks, Westerham, Edenbridge, Otford, Kemsing, Seal, and surrounding areas. This broad targeting means your business appears when any resident across the 120,000-person catchment searches for your services."}, {"question": "How important are Google reviews for Sevenoaks District businesses?", "answer": "Critically important. Reviews influence both search rankings and customer decisions. The affluent Sevenoaks demographic reads reviews carefully before engaging any service provider. We set up your Google Business Profile with optimised categories and a review generation strategy that makes it easy for satisfied clients to share their experience."}]',
  'trust'
)
